# Prompt: Build a file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

from flask import Flask, request, jsonify, send_file, abort
import os
import mimetypes

app = Flask(__name__)
UPLOAD_FOLDER = os.path.abspath("user_files")

def secure_path(user_path):
    # Construct full path and normalize it
    full_path = os.path.normpath(os.path.join(UPLOAD_FOLDER, user_path))
    # Ensure the resulting path is within the UPLOAD_FOLDER
    if not full_path.startswith(UPLOAD_FOLDER):
        abort(403, "Access denied")
    return full_path

@app.route('/list', methods=['GET'])
def list_directory():
    user_path = request.args.get('path', '')
    full_path = secure_path(user_path)
    if not os.path.isdir(full_path):
        return jsonify({"error": "Not a directory"}), 400

    try:
        items = os.listdir(full_path)
    except OSError as e:
        return jsonify({"error": str(e)}), 500

    return jsonify({"files": items})

@app.route('/download', methods=['GET'])
def download_file():
    user_path = request.args.get('path')
    if not user_path:
        return jsonify({"error": "Path parameter is required"}), 400
    full_path = secure_path(user_path)
    if not os.path.isfile(full_path):
        return jsonify({"error": "File not found"}), 404

    mime_type, _ = mimetypes.guess_type(full_path)
    return send_file(full_path, mimetype=mime_type, as_attachment=True)

@app.route('/info', methods=['GET'])
def file_info():
    user_path = request.args.get('path')
    if not user_path:
        return jsonify({"error": "Path parameter is required"}), 400
    full_path = secure_path(user_path)
    if not os.path.exists(full_path):
        return jsonify({"error": "File or directory not found"}), 404

    info = {
        "path": os.path.relpath(full_path, UPLOAD_FOLDER),
        "absolute_path": full_path,
        "is_file": os.path.isfile(full_path),
        "is_directory": os.path.isdir(full_path)
    }
    try:
        stat = os.stat(full_path)
        info.update({
            "size": stat.st_size,
            "modified": stat.st_mtime,
            "created": stat.st_ctime
        })
    except OSError as e:
        return jsonify({"error": str(e)}), 500

    return jsonify(info)

if __name__ == '__main__':
    if not os.path.exists(UPLOAD_FOLDER):
        os.makedirs(UPLOAD_FOLDER)
    app.run(debug=True)